  return String(value).trim();
}
function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}
function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}
function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}
function adFileTimeToDate(value) {
  const raw = clean(value);
  if (!raw || raw === '0' || raw === '9223372036854775807') return null;
  const n = BigInt(raw);
  if (n <= 0n || n >= 9223372036854775807n) return null;
  const ms = Number((n / 10000n) - 11644473600000n);
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? null : d;
}
function parseDate(value) {
  const raw = clean(value);
  if (!raw) return null;
  const d = new Date(raw.includes('T') ? raw : raw.replace(' ', 'T'));
  return Number.isNaN(d.getTime()) ? null : d;
}
function fmtDate(value) {
  const d = value instanceof Date ? value : parseDate(value);
  if (!d) return '';
  return d.toLocaleDateString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' });
}
function fmtDateTime(value) {
  const d = value instanceof Date ? value : parseDate(value);
  if (!d) return '';
  return d.toLocaleString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}
function monthKey(date) {
  const p = new Intl.DateTimeFormat('en-CA', { timeZone: timezone, year: 'numeric', month: '2-digit' }).formatToParts(date);
  const y = p.find(x => x.type === 'year')?.value;
  const m = p.find(x => x.type === 'month')?.value;
  return `${y}-${m}`;
}
function monthLabel(date) {
  return new Intl.DateTimeFormat('es-CL', { timeZone: timezone, year: 'numeric', month: 'long' }).format(date);
}
function diffDays(date) {
  return Math.ceil((date.getTime() - now.getTime()) / 86400000);
}
function getAttr(row, names) {
  for (const name of names) {
    if (row[name] !== undefined && row[name] !== null && row[name] !== '') return row[name];
    const lower = name.toLowerCase();
    const found = Object.keys(row).find(k => k.toLowerCase() === lower);
    if (found && row[found] !== undefined && row[found] !== null && row[found] !== '') return row[found];
  }
  return '';
}

const rows = $input.all().map(i => i.json || {});
const records = [];

for (const row of rows) {
  const expires = adFileTimeToDate(getAttr(row, ['accountExpires', 'accountexpires']));
  if (!expires) continue;
  if (expires < now || expires > until) continue;

  const mail = clean(getAttr(row, ['mail', 'email']));
  const upn = clean(getAttr(row, ['userPrincipalName', 'UserPrincipalName']));
  const displayName = clean(getAttr(row, ['displayName', 'DisplayName']));
  const login = clean(getAttr(row, ['sAMAccountName', 'samaccountname']));
  const office = clean(getAttr(row, ['physicalDeliveryOfficeName', 'office', 'Office']));
  const title = clean(getAttr(row, ['title', 'Title']));
  const department = clean(getAttr(row, ['department', 'Department']));
  const employeeNumber = clean(getAttr(row, ['employeeNumber', 'EmployeeNumber', 'employeeID']));
  const dn = clean(getAttr(row, ['distinguishedName', 'dn']));

  records.push({
    mes_orden: monthKey(expires),
    mes_vencimiento: monthLabel(expires),
    fecha_vencimiento: fmtDate(expires),
    dias_restantes: diffDays(expires),
    email: mail || upn,
    user_principal_name: upn,
    usuario: displayName || login || upn || mail || dn,
    sam_account_name: login,
    employee_number: employeeNumber,
    departamento: office || department,
    puesto: title,
    distinguished_name: dn,
    observacion: `Cuenta AD con vencimiento configurado para ${fmtDate(expires)}. Requiere validacion operativa antes de la fecha indicada.`,
